#include <stdio.h>
#include <stdlib.h>
#define MAX 100000
#define MAX_EDGES 200000
// Define the structure for the graph
typedef struct {
    int u, v;
} Edge;
// Define the structure for the Union-Find algorithm
typedef struct {
    int parent[MAX];
    int rank[MAX];
} UnionFind;
// Function to initialize the Union-Find algorithm
void init(UnionFind *uf, int n) {
    for (int i = 0; i < n; i++) {
        uf->parent[i] = i;
        uf->rank[i] = 0;
    }
}
// Function to find the parent of a node
int find(UnionFind *uf, int x) {
    if (uf->parent[x] != x) {
        uf->parent[x] = find(uf, uf->parent[x]);
    }
    return uf->parent[x];
}
// Function to union two nodes
void unionNodes(UnionFind *uf, int x, int y) {
    int rootX = find(uf, x);
    int rootY = find(uf, y);
    if (rootX != rootY) {
        if (uf->rank[rootX] < uf->rank[rootY]) {
            uf->parent[rootX] = rootY;
        } else if (uf->rank[rootX] > uf->rank[rootY]) {
            uf->parent[rootY] = rootX;
        } else {
            uf->parent[rootY] = rootX;
            uf->rank[rootX]++;
        }
    }
}
// Function to check if a node is in a cycle
int isCycle(UnionFind *uf, int x, int y) {
    return find(uf, x) == find(uf, y);
}
