        if (queries[i][1] == 2) {
            scanf("%d", &queries[i][2]);
        }
    }
    // Apply the operations and answer the queries
    for (int i = 0; i < q; i++) {
        UnionFind uf;
        init(&uf, n);
        for (int j = 0; j < m; j++) {
